import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, PieChart, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentScore {
  score: number;
  rating: string;
}

interface ScoreHistory {
  month: string;
  score: number;
}

interface FactorBreakdown {
  paymentHistory: number;
  creditUtilization: number;
  creditHistoryLength: number;
  newCredit: number;
  creditMix: number;
}

interface CreditData {
  currentScore: CurrentScore;
  scoreHistory: ScoreHistory[];
  factorBreakdown: FactorBreakdown;
}

export default function Widget() {
  const creditData = response.data as CreditData;
  const clipPathId = useId();

  const factorData = Object.entries(creditData.factorBreakdown).map(([key, value]) => ({
    id: key,
    value,
  }));

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Credit Score
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1976D2' }}>
              {creditData.currentScore.score}
            </Typography>
            <Typography variant="caption" sx={{ color: '#1976D2' }}>
              {creditData.currentScore.rating}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: creditData.scoreHistory.map((s) => s.score),
                  color: '#4A90E2',
                  label: 'Score',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: creditData.scoreHistory.map((s) => s.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'scores' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="scores"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Factor Breakdown
            </Typography>
            <PieChart
              height={200}
              series={[{
                data: factorData,
                colorBy: (d) => {
                  switch (d.id) {
                    case 'paymentHistory': return '#4A90E2';
                    case 'creditUtilization': return '#50E3C2';
                    case 'creditHistoryLength': return '#F5A623';
                    case 'newCredit': return '#D0021B';
                    case 'creditMix': return '#B8E986';
                    default: return '#CCC';
                  }
                },
              }]}
              sx={{
                '& .MuiChartsPie-root': {
                  '& .MuiChartsSlice-root': {
                    stroke: '#FFFFFF',
                    strokeWidth: 1,
                  },
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
